// When upstream input is partial (circuit breaker fired), produce partial output — not failure.
// B1 returned 3 matches instead of 20? B2 returns 3 suggestions.
// DataProcessResult.failure is reserved for INFRASTRUCTURE errors, not partial upstream.

// B2 receives from B1:
const { matchedBusinessIds, partialResults } = b1Result.data!;
// partialResults: true when B1 hit 30s timeout

// WRONG: if (partialResults) return DataProcessResult.failure('INSUFFICIENT_MATCHES')
// → blocks onboarding for all users on slow tenants

// CORRECT: forward partial flag, produce N suggestions from N inputs
const suggestions = await Promise.all(
  matchedBusinessIds.map(async (id) => {
    const globalProfile = await this.db.searchDocuments(MATCHING_PROFILES_INDEX, { userId: id });
    return this.buildSuggestion(id, globalProfile.data?.[0], partialResults);
  })
);

// partialResults forwarded to output — UI shows 'finding more connections'
return DataProcessResult.success({
  suggestions,
  partialResults,      // ← forwarded, not swallowed
  suggestionCount: suggestions.length,
});
